		margin: 20px;
}

sp_widget.script:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// UPDATED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------
(function(data) {

    data.page_id = "";
    data.showInactiveProcess = false;
    if (input)
        data.showInactiveProcess = input.showInactiveProcess;
    data.p = data.p || 1;
    data.page_index = (data.p - 1);
    data.window_size = $sp.getValue('maximum_entries') || 10;
    data.window_start = (data.page_index * data.window_size);
    data.window_end = (((data.page_index + 1) * data.window_size));
		// STRY0074534 Template Admins can read any template
		var UserPermissions = new UserInfoScripts();

    var link = '';
    var widgetParams;
    var tabs = [];
    var links = ['link1', 'link2', 'link3', 'link4', 'link5'];
    for (var i = 0; i < links.length; i++) {
        link = options[links[i]];
        // overwriting filter in here...
        if (link) {
            var tab = {};
            widgetParams = getTabData(link);
            // override filter calling JS
            switch (widgetParams.view) {
                case 'MyProcess':
                    // override the my filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getMyTemplateFilter(false);
                    break;
                case 'OUProcess':
                    // override the ou filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getOUTemplateFilter(false);
									break;
                case 'GlobalProcess':
                    // override the ou filter in the page with javascript
                    widgetParams.filter = new tasking_System_Settings_Scripts().getGlobalTemplateFilter(false);
                    break;
            }
						if(data.showInactiveProcess == false){
							widgetParams.filter += '^u_active=true';
						}
            if (widgetParams.table) {
                tab.table = widgetParams.table;
                tab.tabTitle = widgetParams.title;
								tab.o = widgetParams.o;
								tab.d = widgetParams.d;
                tab.filter = widgetParams.filter;
                tab.view = widgetParams.view;
                tab.page_id = widgetParams.page_id;
                tab.tabName = 'tab' + i;
                tab.role = widgetParams.role;
								// STRY0074523  need to check for more than one role here
								var tabVisible = false;
								// STRY0079396 - corrected template permissions
								if(UserPermissions.userHasProcessTemplateAdminRights()){
									tabVisible = true;
								} else if (tab.role=='template_ou' && UserPermissions.userIsOUTemplateDesigner()){
										tabVisible = true;
								} else	if(gs.hasRole(tab.role)){
									tabVisible = true;
								}
								tab.visible = tabVisible; // gs.hasRole(tab.role);// || UserPermissions.userHasProcessTemplateAdminRights();
                tab.count = getTableCountbyFilter(tab.table, tab.filter);
                tab.className = '';
                tab.dataTableWidget = $sp.getWidget('discovertasker-widget-data-table', widgetParams); //widget-data-table
                if (tab.visible)
                    tabs.push(tab);
            }
        }
    }
    if (tabs.length > 0)
        tabs[0].className = 'active';
    data.tabs = tabs;

    function getTabData(link) {
        var table = getParameterByName(link, 'table');
        var view = getParameterByName(link, 'view') || 'sp';
        if (!table) {
            return;
        }


        var widgetParams = {
            table: table,
            o: getParameterByName(link, 'o') || $sp.getValue('order_by'),
            d: getParameterByName(link, 'd') || $sp.getValue('order_direction'),
            p: getParameterByName(link, 'p') || 1,
            view: view,
            fields: $sp.getListColumns(table, view),
            page_id: getParameterByName(link, 'page') || data.page_id || 'form',
            show_keywords: getParameterByName(link, 'show_keywords'),
            show_breadcrumbs: getParameterByName(link, 'show_breadcrumbs'),
            show_new: getParameterByName(link, 'show_new'),
            filter: getParameterByName(link, 'filter'),
            enable_filter: getParameterByName(link, 'enable_filter'),
            window_size: data.window_size,
            title: gs.getMessage(getParameterByName(link, 'title')),
            role: gs.getMessage(getParameterByName(link, 'role')),
            showInactiveProcess: data.showInactiveProcess
        };
        return widgetParams;
    }

    function getParameterByName(url, name) {
        name = name.replace(/[\[\]]/g, "\\$&");
        var regex = new RegExp("[?&]" + name + "(=([^&#]*)|&|#|$)"),
            results = regex.exec(url);
        if (!results) return null;
        if (!results[2]) return '';
        return decodeURIComponent(results[2].replace(/\+/g, " "));
    }


    function getTableCountbyFilter(table, filter) {
        var count;
        var ga = new GlideAggregate(table);
        ga.addEncodedQuery(filter);
        ga.addAggregate('COUNT');

        // only count active processes
        if (table == 'x_153465_discovert_discover_routing_template' && !data.showInactiveProcess) {
            ga.addQuery('u_active', true);
        }
        ga.query();

        if (ga.next()) {
            count = parseInt(ga.getAggregate('COUNT'));

        }
        if (ga == null)
            return;
        else return count;
    }


})(data);
